    std::uint64_t aOrbiterI = 0; std::uint64_t aOrbiterJ = 0; std::uint64_t aOrbiterK = 0;

    // [kdf-a arx]
    std::uint64_t aNonceWordA = TwistMix64::DiffuseB(pNonce * 0xF8FEC3EC52A0CA7BULL + 0xF8FFB5C34F5474A2ULL);
    std::uint64_t aNonceWordB = TwistMix64::DiffuseC(pNonce * 0xD85623C7B9C71D6FULL + 0xB6759CFB5F1FF604ULL);
    std::uint64_t aNonceWordC = TwistMix64::DiffuseC(pNonce * 0x9C236AF978C541CBULL + 0xF237F476126E2235ULL);
    std::uint64_t aNonceWordD = TwistMix64::DiffuseC(pNonce * 0x89693A7BBD5325F9ULL + 0xABB5D4B834F153F0ULL);
