    std::uint64_t aNonceWordF = TwistMix64::DiffuseB(pNonce * 0xD95382CED6B07265ULL + 0xFAD5C5AC1E20DB8CULL);
    std::uint64_t aNonceWordG = TwistMix64::DiffuseC(pNonce * 0xA2018AF1427FD23BULL + 0xB0AA668FEB403836ULL);
    std::uint64_t aNonceWordH = TwistMix64::DiffuseC(pNonce * 0xEFA37C22B0E00D9BULL + 0xE562346D023A031EULL);
    std::uint64_t aNonceWordI = TwistMix64::DiffuseA(pNonce * 0x877CC60CB277940DULL + 0x9AAC863181F84139ULL);
    std::uint64_t aNonceWordJ = TwistMix64::DiffuseC(pNonce * 0x9CBACA50AB081B95ULL + 0xBF3BA402B0AB748DULL);
    std::uint64_t aNonceWordK = TwistMix64::DiffuseB(pNonce * 0xF74B6DE171B95E1BULL + 0xE482C79C857DE291ULL);
    std::uint64_t aNonceWordL = TwistMix64::DiffuseB(pNonce * 0x88F21484B58F306DULL + 0x80797A4A8E29CCA5ULL);
    std::uint64_t aNonceWordM = TwistMix64::DiffuseB(pNonce * 0xC442D4574543478DULL + 0x9C8F8A4C6103C46BULL);
    std::uint64_t aNonceWordN = TwistMix64::DiffuseA(pNonce * 0xE2A16779B5C0F6CDULL + 0xA6009F4759D6B1D2ULL);
