            aOrbiterB = ((((aWandererC + RotL64(aCross, 57U)) + RotL64(aCarry, 47U)) + 16938857689471306365U) + aOrbiterAssignSaltC[((aIndex + 5U)) & S_SALT1]) + aNonceWordP;
