            aOrbiterD = (((aWandererI + RotL64(aScatter, 13U)) + 7452002221814095972U) + aOrbiterAssignSaltD[((aIndex + 17U)) & S_SALT1]) + aNonceWordO;
            aOrbiterE = (aWandererG + RotL64(aIngress, 11U)) + 12901451277406387096U;
            aOrbiterJ = (aWandererE + RotL64(aPrevious, 3U)) + 7829898435958790876U;
