            //
            aOrbiterI = (aOrbiterI + aOrbiterA) + 11197337848540841782U;
            aOrbiterD = ((aOrbiterD ^ aOrbiterI) ^ 13625128193078320691U) ^ aOrbiterUpdateSaltE[((aIndex + 25U)) & S_SALT1];
