            //
            aOrbiterE = (aOrbiterE + aOrbiterB) + 5644667785701681178U;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterE) ^ 7249248716628793529U;
            aOrbiterJ = RotL64((aOrbiterJ * 15108894973148191643U), 23U);
            //
            aOrbiterH = ((aOrbiterH + aOrbiterG) + 1798417136326192136U) + aOrbiterUpdateSaltD[(((31U - aIndex) + 3U)) & S_SALT1];
            aOrbiterI = (aOrbiterI ^ aOrbiterH) ^ 10824619890473044754U;
            aOrbiterI = RotL64((aOrbiterI * 8515673931467231753U), 19U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterD) + 8551334895710761141U;
            aOrbiterH = ((aOrbiterH ^ aOrbiterC) ^ 11918929516657924614U) ^ aOrbiterUpdateSaltC[(((31U - aIndex) + 8U)) & S_SALT1];
            aOrbiterH = RotL64((aOrbiterH * 13601418361598277619U), 21U);
            //
            aOrbiterD = (aOrbiterD + aOrbiterE) + 9962865117139365673U;
            aOrbiterG = (aOrbiterG ^ aOrbiterD) ^ 4181660569230696634U;
            aOrbiterG = RotL64((aOrbiterG * 11397114184113529379U), 5U);
            //
            aOrbiterG = ((aOrbiterG + aOrbiterJ) + 13287367149064710557U) + aNonceWordB;
            aOrbiterA = (aOrbiterA ^ aOrbiterG) ^ 11645058021081175044U;
            aOrbiterA = RotL64((aOrbiterA * 11171847233626202531U), 51U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterI) + 8327692147210503374U;
            aOrbiterC = (aOrbiterC ^ aOrbiterK) ^ 11453353816249429421U;
            aOrbiterC = RotL64((aOrbiterC * 15039531965091111529U), 53U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterK) + 12814585678256055120U;
            aOrbiterF = ((aOrbiterF ^ aOrbiterJ) ^ 10840403272357110502U) ^ aNonceWordE;
            aOrbiterF = RotL64((aOrbiterF * 13000449866337239719U), 57U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterC) + 7243241166046703432U;
            aOrbiterB = (aOrbiterB ^ aOrbiterF) ^ 9995231459738784281U;
            aOrbiterB = RotL64((aOrbiterB * 15305788851130535991U), 39U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterF) + 17574706478799087499U;
            aOrbiterE = (aOrbiterE ^ aOrbiterA) ^ 16508856563422519762U;
            aOrbiterE = RotL64((aOrbiterE * 7889597557156316077U), 43U);
            //
            aIngress = RotL64(aOrbiterI, 6U) ^ aOrbiterB;
            aIngress = aIngress + (aOrbiterK ^ RotL64(aOrbiterG, 39U));
            aIngress = aIngress + (aOrbiterF ^ RotL64(aOrbiterC, 21U));
            aIngress = aIngress + (aOrbiterD ^ RotL64(aOrbiterJ, 41U));
            aIngress = aIngress + (aOrbiterA ^ RotL64(aOrbiterE, 43U));
