            aIngress = TwistMix64::DiffuseB((aIngress + aScatter));
            //
            aWandererJ = aWandererJ + (((RotL64(aScatter, 51U) + RotL64(aOrbiterF, 4U)) + aOrbiterJ) + aNonceWordM);
            aWandererC = aWandererC ^ (((RotL64(aCross, 10U) + aOrbiterI) + RotL64(aOrbiterA, 29U)) + aNonceWordF);
