            aWandererA = aWandererA ^ ((RotL64(aScatter, 27U) + aOrbiterA) + RotL64(aOrbiterK, 41U));
            aWandererB = aWandererB + (((RotL64(aPrevious, 47U) + RotL64(aOrbiterF, 18U)) + aOrbiterE) + RotL64(aCarry, 51U));
            aWandererJ = aWandererJ ^ ((RotL64(aIngress, 5U) + RotL64(aOrbiterK, 11U)) + aOrbiterI);
