            aScatter = (RotL64(aCross, 14U) + RotL64(aPrevious, 57U)) ^ (RotL64(aIngress, 39U) + RotL64(aCarry, 27U));
            aScatter = TwistMix64::DiffuseB(aScatter);
            //
            aOrbiterF = (aWandererF + RotL64(aIngress, 13U)) + 17461834701849411739U;
            aOrbiterA = (aWandererK + RotL64(aCross, 29U)) + 11621417462469091698U;
