            aOrbiterH = (aOrbiterH + aOrbiterE) + 17921440342691103926U;
            aOrbiterJ = ((aOrbiterJ ^ aOrbiterH) ^ 8244858311082869773U) ^ aPhaseHOrbiterUpdateSaltD[(((31U - aIndex) + 12U)) & S_SALT1];
