            aOrbiterE = RotL64((aOrbiterE * 14161675172737750987U), 27U);
            //
            aOrbiterJ = ((aOrbiterJ + aOrbiterK) + 1732498314006654825U) + aPhaseHOrbiterUpdateSaltF[(((31U - aIndex) + 25U)) & S_SALT1];
            aOrbiterI = ((aOrbiterI ^ aOrbiterJ) ^ 18039596115730684909U) ^ aPhaseHOrbiterUpdateSaltC[((aIndex + 8U)) & S_SALT1];
            aOrbiterI = RotL64((aOrbiterI * 3360585757484104559U), 5U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterJ) + 11012180863998931822U;
            aOrbiterA = (aOrbiterA ^ aOrbiterG) ^ 6988235414869987452U;
